import { $input } from 'n8n-workflow';

// Add after AI Agent node
const aiOutput = $input.first().json.aiResponse;

// Bias detection using simple keyword analysis
const biasedTerms = {
  gender: ['man', 'woman', 'male', 'female'],
  race: ['black', 'white', 'asian'],
  age: ['young', 'old', 'elderly']
};

let biasScore = 0;
const lowerText = aiOutput.toLowerCase();

Object.values(biasedTerms).forEach(terms => {
  terms.forEach(term => {
    if (lowerText.includes(term)) biasScore += 1;
  });
});

return {
  json: {
    originalOutput: aiOutput,
    biasScore,
    isBiased: biasScore > 2,
    flagged: biasScore > 2 ? 'BLOCKED' : 'APPROVED'
  }
};

// n8n Code Node - Demographic Bias Detector
const inputData = $input.all();

const protectedClasses = {
  gender: ['he', 'she', 'him', 'her', 'mr', 'ms', 'mrs'],
  raceEthnicity: ['black', 'white', 'latino', 'asian'],
  age: ['young', 'old', 'kid', 'senior'],
  disability: ['blind', 'deaf', 'wheelchair']
};

return inputData.map(item => {
  const text = item.json.aiResponse || '';
  const lowerText = text.toLowerCase();

  const counts = {};
  Object.entries(protectedClasses).forEach(([category, terms]) => {
    counts[category] = terms.filter(term => lowerText.includes(term)).length;
  });

  const totalBiasHits = Object.values(counts).reduce((a, b) => a + b, 0);

  return {
    json: {
      ...item.json,
      biasAnalysis: {
        ...counts,
        totalBiasHits,
        riskLevel: totalBiasHits > 1 ? 'HIGH' : totalBiasHits > 0 ? 'MEDIUM' : 'LOW'
      }
    }
  };
});

// Detects if sentiment differs when mentioning protected groups
const analyzeSentimentBias = (text: string) => {
  const positiveWords = ['great', 'excellent', 'amazing', 'wonderful'];
  const negativeWords = ['terrible', 'awful', 'horrible', 'bad'];

  const lowerText = text.toLowerCase();
  const posScore = positiveWords.filter(w => lowerText.includes(w)).length;
  const negScore = negativeWords.filter(w => lowerText.includes(w)).length;

  return { posScore, negScore, sentiment: posScore - negScore };
};

// Protected group detector
const protectedGroups = ['woman', 'black', 'asian', 'disabled', 'senior'];

const aiText = $input.first().json.aiResponse;
const sentiment = analyzeSentimentBias(aiText);

let biasDetected = false;
protectedGroups.forEach(group => {
  if (aiText.toLowerCase().includes(group)) {
    biasDetected = true;
  }
});

return {
  json: {
    aiResponse: aiText,
    sentiment,
    containsProtectedGroups: biasDetected,
    biased: biasDetected && Math.abs(sentiment.sentiment) > 1
  }
};

