if (input.biasAnalysis?.totalBiasHits && input.biasAnalysis.totalBiasHits > 1) {
  // Route to human review or neutral response
  return {
    json: {
      status: 'BLOCKED',
      reason: 'High bias score detected',
      originalOutput: input.aiResponse,
      biasScore: input.biasAnalysis.totalBiasHits,
      action: 'SEND_TO_REVIEW'
    }
  };
}

// Safe to proceed
return {
  json: {
    status: 'APPROVED',
    ...input
  }
};

// Neutralizes biased language in AI responses
const neutralizeBias = (biasedText: string) => {
  const replacements = {
    'he is': 'they are',
    'she is': 'they are',
    'young people': 'people',
    'old customers': 'customers',
    'black': 'diverse',
    'white': 'diverse'
  };

  let neutral = biasedText;
  Object.entries(replacements).forEach(([bad, good]) => {
    neutral = neutral.replace(new RegExp(bad, 'gi'), good);
  });

  return neutral;
};

const input = $input.first().json;

if (input.isBiased) {
  const neutralResponse = neutralizeBias(input.aiResponse);
  return {
    json: {
      original: input.aiResponse,
      neutralized: neutralResponse,
      status: 'NEUTRALIZED',
      useNeutralized: true
    }
  };
}

return { json: input };

// Pre-process AI Agent prompts to enforce fairness
const originalPrompt = $input.first().json.prompt;

const fairnessInstructions = `
CRITICAL: Ensure responses are:
1. Gender neutral (use 'they' instead of he/she)
2. Race/ethnicity agnostic
3. Age neutral
4. Ability neutral
5. Never make assumptions about demographics

Flag if you detect potential bias in your reasoning.`;

const fairPrompt = originalPrompt + fairnessInstructions;

return {
  json: {
    originalPrompt,
    fairPrompt,
    status: 'ENHANCED_FOR_FAIRNESS'
  }
};

