import { Vex } from '@vex_dev/sdk';

// n8n Webhook Node - Vex Integration
const vex = new Vex({
  projectId: 'your-vex-project-id',
  webhookSecret: process.env.VEX_WEBHOOK_SECRET
});

// Capture AI Agent output
export default defineWebhookHandler(async (event) => {
  const aiOutput = event.body;

  // Vex bias detection for n8n workflows
  const result = await vex.detect({
    type: 'AI_BIAS_N8N',
    payload: {
      aiResponse: aiOutput.aiResponse,
      workflowId: $execution.id,
      nodeName: $node.name,
      executionContext: {
        isRecursive: $execution.parentExecutionId !== null,
        memoryWindowSize: aiOutput.memory?.length || 0
      }
    }
  });

  if (result.isBiased) {
    // Auto-remediate
    const neutralResponse = await vex.remediate({
      biasedOutput: aiOutput.aiResponse,
      context: 'n8n-workflow',
      complianceLevel: 'STRICT'
    });

    return {
      status: 'REMEDIATED',
      original: aiOutput.aiResponse,
      neutral: neutralResponse,
      biasScore: result.score,
      workflowBlocked: true
    };
  }

  // Safe to proceed
  return { status: 'APPROVED', ...aiOutput };
});
